select

from cer_project_tb


        and id = #{id,jdbcType=INTEGER}


        and task_num in
        (select a.task_num from bio_task_dtl_tb a inner JOIN
        (select instance_id from flow_his_task_actor_tb where actor_id =#{actorId,jdbcType=INTEGER}
        UNION ALL
        select instance_id from flow_task_actor_tb where actor_id =#{actorId,jdbcType=INTEGER}) b on a.instance_id=b.instance_id)


        and project_name = #{projectName,jdbcType=VARCHAR}


        and project_type = #{projectType,jdbcType=VARCHAR}


        and project_code = #{projectCode,jdbcType=VARCHAR}


        and project_status = #{projectStatus,jdbcType=VARCHAR}


        and create_time = #{createTime,jdbcType=TIMESTAMP}


        and update_time = #{updateTime,jdbcType=TIMESTAMP}


        and create_user_id = #{createUserId,jdbcType=INTEGER}


        and owner_user_id = #{ownerUserId,jdbcType=INTEGER}


        and create_user_name = #{createUserName,jdbcType=VARCHAR}


        and owner_user_name = #{ownerUserName,jdbcType=VARCHAR}


        and gene_edit_method = #{geneEditMethod,jdbcType=VARCHAR}


        and expect_start_date = #{expectStartDate,jdbcType=VARCHAR}


        and task_num = #{taskNum,jdbcType=VARCHAR}


        and project_category_code = #{projectCategoryCode,jdbcType=VARCHAR}





            order by project_code ${orderType}


            order by id ${orderType}



        order by id desc

